import { chromium } from 'playwright';
import path from 'path';

const BASE_URL = 'https://nexus-ai-silk-six.vercel.app';
const SCREENSHOT_DIR = 'C:/Users/User/nexus-ai/test-screenshots/tour';
const VIEWPORT = { width: 1440, height: 900 };

const EMAIL = 'testuser@nexusai-test.com';
const PASSWORD = 'TestPassword123!';

async function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function screenshot(page, name, fullPage = false) {
  await delay(1500); // wait for animations/rendering
  await page.screenshot({
    path: path.join(SCREENSHOT_DIR, name),
    fullPage: fullPage,
  });
  console.log(`  [OK] ${name}`);
}

async function waitForLoad(page) {
  try {
    await page.waitForLoadState('networkidle', { timeout: 15000 });
  } catch {
    await page.waitForLoadState('domcontentloaded', { timeout: 10000 });
  }
  await delay(1000);
}

(async () => {
  console.log('Launching browser...');
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: VIEWPORT,
    deviceScaleFactor: 1,
  });
  const page = await context.newPage();

  try {
    // ============================================================
    // PUBLIC PAGES
    // ============================================================

    // 1. Landing page
    console.log('\n--- PUBLIC PAGES ---');
    console.log('1. Landing page (/)');
    await page.goto(`${BASE_URL}/`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-01-landing.png');

    // 2. Scroll to features section
    console.log('2. Features section');
    // Try to find a features section by common selectors
    const featuresSection = await page.$('#features, [id*="feature"], section:has(h2:text-matches("feature", "i"))');
    if (featuresSection) {
      await featuresSection.scrollIntoViewIfNeeded();
    } else {
      // Scroll down a good amount
      await page.evaluate(() => window.scrollBy(0, window.innerHeight * 1.2));
    }
    await delay(1000);
    await screenshot(page, 'tour-02-features.png');

    // 3. Scroll to pricing section
    console.log('3. Pricing section');
    const pricingSection = await page.$('#pricing, [id*="pricing"], section:has(h2:text-matches("pricing", "i"))');
    if (pricingSection) {
      await pricingSection.scrollIntoViewIfNeeded();
    } else {
      await page.evaluate(() => window.scrollBy(0, window.innerHeight * 2));
    }
    await delay(1000);
    await screenshot(page, 'tour-03-pricing.png');

    // 4. Pricing page
    console.log('4. Pricing page (/pricing)');
    await page.goto(`${BASE_URL}/pricing`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-04-pricing-page.png');

    // ============================================================
    // AUTH FLOW
    // ============================================================
    console.log('\n--- AUTH FLOW ---');

    // 5. Login page
    console.log('5. Login page (/login)');
    await page.goto(`${BASE_URL}/login`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-05-login.png');

    // 6. Login with credentials
    console.log('6. Logging in...');
    // Try to find email/password fields
    const emailInput = await page.$('input[type="email"], input[name="email"], input[placeholder*="email" i], input[placeholder*="Email"]');
    const passwordInput = await page.$('input[type="password"], input[name="password"]');

    if (emailInput && passwordInput) {
      await emailInput.click();
      await emailInput.fill(EMAIL);
      await passwordInput.click();
      await passwordInput.fill(PASSWORD);
      await delay(500);

      // Find and click submit button
      const submitBtn = await page.$('button[type="submit"], button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login"), button:has-text("Se connecter")');
      if (submitBtn) {
        await submitBtn.click();
        console.log('  Clicked login button, waiting for redirect...');
      }
    } else {
      console.log('  Could not find email/password fields, trying alternative selectors...');
      // Try broader selectors
      const inputs = await page.$$('input');
      console.log(`  Found ${inputs.length} input fields`);
      if (inputs.length >= 2) {
        await inputs[0].fill(EMAIL);
        await inputs[1].fill(PASSWORD);
        const buttons = await page.$$('button');
        for (const btn of buttons) {
          const text = await btn.textContent();
          if (text && (text.toLowerCase().includes('sign') || text.toLowerCase().includes('log') || text.toLowerCase().includes('connect'))) {
            await btn.click();
            break;
          }
        }
      }
    }

    // 7. Wait for dashboard redirect
    console.log('7. Waiting for dashboard redirect...');
    try {
      await page.waitForURL('**/dashboard**', { timeout: 15000 });
      console.log('  Redirected to dashboard!');
    } catch {
      console.log('  No automatic redirect to /dashboard, navigating manually...');
      // Check current URL
      console.log(`  Current URL: ${page.url()}`);
      await delay(3000);
      console.log(`  URL after wait: ${page.url()}`);
    }
    await waitForLoad(page);

    // ============================================================
    // DASHBOARD TOUR
    // ============================================================
    console.log('\n--- DASHBOARD TOUR ---');

    // 8. Dashboard overview
    console.log('8. Dashboard overview');
    await page.goto(`${BASE_URL}/dashboard`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-06-dashboard.png');

    // 9. Documents page
    console.log('9. Documents page');
    await page.goto(`${BASE_URL}/dashboard/documents`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-07-documents.png');

    // 10. Upload page
    console.log('10. Upload page');
    await page.goto(`${BASE_URL}/dashboard/upload`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-08-upload.png');

    // 11. Templates page
    console.log('11. Templates page');
    await page.goto(`${BASE_URL}/dashboard/templates`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-09-templates.png');

    // 12. Create Template page
    console.log('12. Create Template page');
    await page.goto(`${BASE_URL}/dashboard/templates/new`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-10-create-template.png');

    // 13. Surveys page
    console.log('13. Surveys page');
    await page.goto(`${BASE_URL}/dashboard/surveys`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-11-surveys.png');

    // 14. Create Survey page
    console.log('14. Create Survey page');
    await page.goto(`${BASE_URL}/dashboard/surveys/new`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-12-create-survey.png');

    // 15. Settings/General
    console.log('15. Settings page');
    await page.goto(`${BASE_URL}/dashboard/settings`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-13-settings.png');

    // 16. Team page
    console.log('16. Team page');
    await page.goto(`${BASE_URL}/dashboard/team`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-14-team.png');

    // 17. Billing page
    console.log('17. Billing page');
    await page.goto(`${BASE_URL}/dashboard/billing`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-15-billing.png');

    // 18. API Keys page
    console.log('18. API Keys page');
    await page.goto(`${BASE_URL}/dashboard/api-keys`, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForLoad(page);
    await screenshot(page, 'tour-16-api-keys.png');

    console.log('\n=== TOUR COMPLETE ===');
    console.log(`All screenshots saved to: ${SCREENSHOT_DIR}`);

  } catch (err) {
    console.error('Error during tour:', err.message);
    // Take an error screenshot
    try {
      await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'error-screenshot.png') });
      console.log('Error screenshot saved.');
    } catch {}
  } finally {
    await browser.close();
  }
})();

